// Forge CLIFF/SIDE material slabs — flat front-view cross-sections (lip → body → base)
// generated by codex and METHOD-VERIFIED via the shared codex-imagegen helper (an
// image_generation_call event must appear in the session ROLLOUT — see codex-imagegen.mjs).
// These are FLAT slabs; project-tile-side.py skews them onto the two iso cliff parallelograms
// (so codex never draws our iso angle — the known PixelLab/codex iso failure) and bakes the
// upper-left lighting. Art direction per the rich-side research (ADR-0039 side layer).
//
//   node frontend/scripts/forge-side-texture.mjs [families] --slot-prefix <slot> -- <upload options>
import { mkdtempSync, rmSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { CODEX, runCodex, imageGenVerdict, sessionImage } from './codex-imagegen.mjs';
import { optionValue, splitGeneratorArgs, uploadGeneratedCandidate } from './upload-generated-candidate.mjs';

// Flat front-view cliff cross-sections. "no isometric skew" — the projection adds the angle.
const SPECS = [
  {
    name: 'grass',
    body: 'a grassy earth cliff cross-section: a band of lush green turf at the very top overhanging the edge and casting a soft shadow, then 3 horizontal soil strata in warm browns getting darker toward the bottom, small pebbles scattered in the soil, and a few thin pale tree roots dangling down from under the turf',
    palette: 'turf greens up top (#4f7a2e, #6f9e42 highlights), warm soil browns (#7a5a36, #5c4226), cool dark base #2c2014; roots one step lighter than the soil',
  },
  {
    name: 'dirt',
    body: 'a dry dirt embankment cross-section: 5-6 horizontal sediment strata in ochre-to-umber browns, embedded small pebbles denser toward the bottom, two buried rounded stones near the base, and a couple of faint vertical erosion channels',
    palette: 'ochre #9a7340, umber #6e4f2c, cool shadow brown #3a2a1a; low-contrast crumbly grain, lit pebbles top-left',
  },
  {
    name: 'stone',
    body: 'a weathered mossy bedrock cliff cross-section: a few large irregular stone blocks separated by deep dark cracks with branching fissures, a couple of protruding rocks casting small shadows, patches of green moss on the upper edges and inside the crevices, faint lichen speckle, and one damp vertical drip streak',
    palette: 'cool stone greys (#3a4045, #4a5258, #5b636a), moss green #4a6b30, shadow brown in cracks, cream highlight #8a9298',
  },
  {
    name: 'sand',
    body: 'a sandstone cliff cross-section: horizontal wind-eroded shelves stacked vertically, each catching a thin warm highlight on its top lip with a soft shadow beneath, gentle overhangs, smooth low-contrast sandy grain, and a little loose sand trickling at the base',
    palette: 'pale gold #cdb074, tan #a8854f, warm shadow #6e5230; soft, warm, low-contrast',
  },
  {
    name: 'pebble',
    body: 'a riverstone cobble bank cross-section: tightly packed rounded pebbles of varied sizes getting smaller toward the bottom, each lit from upper-left with dark gaps between them, and a little moss and soil filling the lowest crevices',
    palette: 'mixed cool and warm greys (#4a4f55, #6a6f76, #868c92) with two warm accent stones, deep dark gap shadows',
  },
];

function prompt(spec, prior) {
  return `IMAGE-GENERATION task: create ONE PNG by GENERATING it with the built-in image_gen tool (the imagegen skill). Do NOT hand-draw it with code (PIL/Pillow, cairo, matplotlib, SVG, HTML/CSS, canvas), do NOT write a script, and do NOT crop or extract from any file — programmatic output is automatically rejected and you will be asked again.${prior ? `\n\nYOUR PREVIOUS ATTEMPT WAS REJECTED: ${prior}\n` : ''}

Generate a FLAT FRONT-VIEW pixel-art CLIFF CROSS-SECTION of ${spec.body}. It is the vertical face of a cut-away bank, seen straight-on (NO isometric skew, NO perspective, NO 3D — that is added later). It fills the whole canvas top to bottom as one continuous cliff face.

STYLE — most important: detailed PIXEL ART like a high-quality modern 16-bit game environment (Octopath Traveler, Eastward, FFT cliff faces). A limited but rich harmonious palette; fine yet clearly VISIBLE pixels; tasteful dithering. It MUST read as crafted pixel art — NOT a photograph, NOT smooth/painterly, NOT a 3D render. No blur, no soft gradients, no anti-aliasing, no glossy highlights.

LIGHTING: light comes from the UPPER-LEFT. The very top (the lip) is the lightest band; value steps DARKER toward the bottom (the base falls into shadow). Carve a few dark crevices/cracks (ambient occlusion) and pop a couple of small protrusions with a 1px top highlight and a small shadow cast down-right. Break it up so NO region looks like a flat fill and there is no repeating motif.

PALETTE (build the limited palette from these): ${spec.palette}.

Fill the entire canvas edge to edge with the cliff material — fully opaque, no border, frame, vignette, ground line, sky, or text. Just the cliff face.

Save it as ./${spec.name}.png in the current working directory, then stop.`;
}

async function forgeOne(spec, maxTries, ref) {
  let prior = '';
  for (let attempt = 1; attempt <= maxTries; attempt += 1) {
    const work = mkdtempSync(join(tmpdir(), `side-${spec.name}-`));
    try {
      const text = prompt(spec, prior) + (ref
        ? '\n\nVISUAL REFERENCE: an attached photo of a real mountainside is provided. Use it as reference for the rock shapes, strata, weathering, and the grass/rock colour — but RE-RENDER the scene as the pixel-art cliff cross-section described above. Do NOT copy the photo literally and keep zero photographic detail; it informs the forms only.'
        : '');
      const { out: jsonl } = await runCodex(work, text, ref);
      const verdict = imageGenVerdict(jsonl);
      if (!verdict.ok) {
        console.log(`  ${spec.name} try ${attempt}: METHOD ✗ — ${verdict.reason}`);
        prior = 'the rollout shows you did NOT emit an image_generation_call — you hand-drew the PNG in code. You MUST use the built-in image_gen tool to GENERATE it as a real bitmap.';
        continue;
      }
      const shipped = sessionImage(verdict.tid);
      if (!shipped) {
        console.log(`  ${spec.name} try ${attempt}: generated but no ig_*.png under generated_images/${verdict.tid} — retrying`);
        prior = 'you generated an image but it could not be located; generate again and leave the output in the default folder.';
        continue;
      }
      const file = `${spec.name}-side-slab-${spec.idx}.png`;
      const provenance = join(work, 'provenance.json');
      writeFileSync(provenance, `${JSON.stringify({ generator: 'forge-side-texture', threadId: verdict.tid, family: spec.name, index: spec.idx }, null, 2)}\n`);
      uploadGeneratedCandidate(shipped, [...uploadArgs, '--provenance-json', provenance], `${slotPrefix}/${file}`);
      console.log(`  ${spec.name} try ${attempt}: image_generation_call ✓ -> ${slotPrefix}/${file}`);
      return { name: spec.name, pass: true, tries: attempt };
    } finally {
      rmSync(work, { recursive: true, force: true });
    }
  }
  return { name: spec.name, pass: false, tries: maxTries };
}

const { toolArgs, uploadArgs } = splitGeneratorArgs(process.argv.slice(2));
const slotPrefix = optionValue(toolArgs, '--slot-prefix').replace(/\/+$/, '');
if (!slotPrefix || !uploadArgs.length) throw new Error('forge-side-texture requires --slot-prefix and live-media options after --');
const prefixIndex = toolArgs.indexOf('--slot-prefix');
const argv = toolArgs.filter((_, index) => index !== prefixIndex && index !== prefixIndex + 1);
const flag = (n, def) => { const i = argv.indexOf(n); return i >= 0 ? argv[i + 1] : def; };
const n = Math.max(1, parseInt(flag('--n', '3'), 10));
const maxTries = Math.max(1, parseInt(flag('--tries', '2'), 10));
const idx = Math.max(0, parseInt(flag('--index', '0'), 10));
const ref = flag('--ref', null);
const VALUE_FLAGS = ['--n', '--tries', '--index', '--ref'];
const names = argv.filter((a) => !a.startsWith('--') && !VALUE_FLAGS.includes(argv[argv.indexOf(a) - 1]));
const queue = (argv.includes('--all') || !names.length ? SPECS : SPECS.filter((s) => names.includes(s.name))).map((s) => ({ ...s, idx }));

console.log(`forge-side-texture: ${queue.length} slab(s), concurrency ${n}, up to ${maxTries} tries\n  codex: ${CODEX}\n`);
let i = 0; const results = [];
const worker = async () => { while (i < queue.length) { const s = queue[i]; i += 1; results.push(await forgeOne(s, maxTries, ref)); } };
await Promise.all(Array.from({ length: Math.min(n, queue.length) }, worker));
const ok = results.filter((r) => r.pass).length;
console.log(`\n==== ${ok}/${results.length} forged ====`);
if (ok < results.length) console.log('  FAILED:', results.filter((r) => !r.pass).map((r) => r.name).join(', '));
